const Redis = require('ioredis');

const redis = new Redis({ host: 'redis', port: 6379 });

try {
  const patientIds = await redis.smembers('patients');

  const patients = await Promise.all(
    patientIds.map(async (id) => {
      const p = await redis.hgetall(`patient:${id}`);
      const contactCount = await redis.llen(`patient:${id}:contacts`);
      const photoCount = await redis.llen(`patient:${id}:photos`);
      return {
        patientId: id,
        name: p.name,
        deviceId: p.deviceId || null,
        status: p.status,
        createdAt: p.createdAt,
        contactCount,
        photoCount
      };
    })
  );

  await redis.quit();
  return [{ json: { patients } }];
} catch (err) {
  await redis.quit().catch(() => {});
  throw err;
}
